"using Microsoft.Extensions.Logging;
using ReleasePilot.Application.Ports;
using ReleasePilot.Domain.ValueObjects;

namespace ReleasePilot.Infrastructure.Adapters;

public class InMemoryDeploymentPort : IDeploymentPort
{
    private readonly ILogger<InMemoryDeploymentPort> _logger;
    private readonly int _delayMs;

    public InMemoryDeploymentPort(ILogger<InMemoryDeploymentPort> logger) : this(logger, 0)
    {
    }

    public InMemoryDeploymentPort(ILogger<InMemoryDeploymentPort> logger, int delayMs)
    {
        _logger = logger;
        _delayMs = delayMs;
    }

    public async Task TriggerAsync(PromotionId id, CancellationToken ct)
    {
        _logger.LogInformation("Deployment was triggered for promotionId: {PromotionId}", id.Value);
        if (_delayMs > 0)
        {
            await Task.Delay(_delayMs, ct);
        }
    }
}
"

"using System.Collections.Concurrent;
using Microsoft.Extensions.Logging;
using ReleasePilot.Application.Ports;
using ReleasePilot.Domain.Enums;
using ReleasePilot.Domain.ValueObjects;

namespace ReleasePilot.Infrastructure.Adapters;

public class InMemoryNotificationPort(ILogger<InMemoryNotificationPort> logger) : INotificationPort
{
    public ConcurrentBag<string> NotificationsSent { get; } = new();

    public Task NotifyTerminalStateAsync(PromotionId id, PromotionStatus status, CancellationToken ct)
    {
        var message = $"Promotion {id.Value} reached terminal status {status}";
        logger.LogInformation("PromotionId: {PromotionId}, Terminal Status: {Status}", id.Value, status);
        NotificationsSent.Add(message);
        return Task.CompletedTask;
    }
}
"

"using ReleasePilot.Application.Ports;
using ReleasePilot.Domain.ValueObjects;

namespace ReleasePilot.Infrastructure.Adapters;

public class InMemoryIssueTrackerPort : IIssueTrackerPort
{
    public Task<IReadOnlyList<WorkItemDto>> GetLinkedItemsAsync(PromotionId id, CancellationToken ct)
    {
        IReadOnlyList<WorkItemDto> workItems =
        [
            new WorkItemDto("ISSUE-1", "Add login feature", "https://issues.example.com/1"),
            new WorkItemDto("ISSUE-2", "Fix signup bug", "https://issues.example.com/2")
        ];

        return Task.FromResult(workItems);
    }
}
"

